def countInversions(arr):
    n = len(arr)
    if n <= 1:
        return 0

    temp_arr = [0] * n

    def _mergeSortAndCount(arr, temp_arr, left, right):
        inversions = 0
        if left < right:
            mid = (left + right) // 2

            inversions += _mergeSortAndCount(arr, temp_arr, left, mid)
            inversions += _mergeSortAndCount(arr, temp_arr, mid + 1, right)

            inversions += _mergeAndCountSplitInversions(arr, temp_arr, left, mid, right)
        return inversions

    def _mergeAndCountSplitInversions(arr, temp_arr, left, mid, right):
        i = left       
        j = mid + 1    
        k = left       

        inversions = 0

        while i <= mid and j <= right:
            if arr[i] <= arr[j]:
                temp_arr[k] = arr[i]
                i += 1
            else:
                temp_arr[k] = arr[j]
                inversions += (mid - i + 1)
                j += 1
            k += 1

        while i <= mid:
            temp_arr[k] = arr[i]
            i += 1
            k += 1

        while j <= right:
            temp_arr[k] = arr[j]
            j += 1
            k += 1

        for idx in range(left, right + 1):
            arr[idx] = temp_arr[idx]

        return inversions

    return _mergeSortAndCount(arr, temp_arr, 0, n - 1)
